Declaring inventory slot structures and item data asset references:

```cpp
#include

UCLASS()
class UItemDataAsset : public UPrimaryDataAsset {
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly, Category =

)
    FText ItemName;
};

USTRUCT(BlueprintType)
struct FItemSlot {
    GENERATED_BODY()

    UPROPERTY(EditAnywhere, BlueprintReadOnly)
    UItemDataAsset* ItemData = nullptr;

    UPROPERTY(EditAnywhere, BlueprintReadOnly)
    int32 StackCount = 1;
};
```
